// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract PragmaOracle {
    address public admin;
    mapping(address => bool) public dataProviders;
    mapping(bytes32 => uint256) public dataFeeds;

    event DataFeedUpdated(bytes32 indexed key, uint256 value, address indexed provider);
    event DataProviderRoleGranted(address indexed provider);
    event DataProviderRoleRevoked(address indexed provider);

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier onlyDataProvider() {
        require(dataProviders[msg.sender], "Not data provider");
        _;
    }

    constructor() {
        admin = msg.sender;
    }

    function updateDataFeed(bytes32 key, uint256 value, bytes memory signature) public onlyDataProvider {
        require(verifySignature(key, value, signature), "Invalid signature");
        dataFeeds[key] = value;
        emit DataFeedUpdated(key, value, msg.sender);
    }

    function verifySignature(bytes32 key, uint256 value, bytes memory signature) public view returns (bool) {
        bytes32 message = keccak256(abi.encodePacked(key, value));
        address signer = recoverSigner(message, signature);
        return signer == admin;
    }

    function recoverSigner(bytes32 message, bytes memory signature) internal pure returns (address) {
        require(signature.length == 65, "Invalid signature length");
        bytes32 r;
        bytes32 s;
        uint8 v;
        assembly {
            r := mload(add(signature, 0x20))
            s := mload(add(signature, 0x40))
            v := byte(0, mload(add(signature, 0x60)))
        }
        if (v < 27) {
            v += 27;
        }
        require(v == 27 || v == 28, "Invalid signature v value");
        return ecrecover(message, v, r, s);
    }

    function grantDataProviderRole(address provider) public onlyAdmin {
        dataProviders[provider] = true;
        emit DataProviderRoleGranted(provider);
    }

    function revokeDataProviderRole(address provider) public onlyAdmin {
        dataProviders[provider] = false;
        emit DataProviderRoleRevoked(provider);
    }
}
