// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
import "forge-std/Test.sol";
import "./PragmaOracle.sol";

contract PragmaOracleTest is Test {
    PragmaOracle oracle;
    address admin = address(0x1);
    address provider1 = address(0x2);
    address provider2 = address(0x3);

    function setUp() public {
        vm.prank(admin);
        oracle = new PragmaOracle();
        oracle.grantDataProviderRole(provider1);
        oracle.grantDataProviderRole(provider2);
    }

    function testUpdateDataFeed() public {
        bytes32 key = keccak256("price");
        uint256 value = 100;
        bytes memory signature = signMessage(key, value, admin);
        vm.prank(provider1);
        oracle.updateDataFeed(key, value, signature);
        assertEq(oracle.dataFeeds(key), value);
    }

    function testVerifySignature() public {
        bytes32 key = keccak256("price");
        uint256 value = 100;
        bytes memory signature = signMessage(key, value, admin);
        assertTrue(oracle.verifySignature(key, value, signature));
    }

    function testRecoverSigner() public {
        bytes32 key = keccak256("price");
        uint256 value = 100;
        bytes memory signature = signMessage(key, value, admin);
        address signer = oracle.recoverSigner(keccak256(abi.encodePacked(key, value)), signature);
        assertEq(signer, admin);
    }

    function testOnlyAdminCanGrantRole() public {
        vm.prank(provider1);
        vm.expectRevert("Not admin");
        oracle.grantDataProviderRole(provider2);
    }

    function testOnlyAdminCanRevokeRole() public {
        vm.prank(provider1);
        vm.expectRevert("Not admin");
        oracle.revokeDataProviderRole(provider2);
    }

    function testOnlyDataProviderCanUpdateFeed() public {
        bytes32 key = keccak256("price");
        uint256 value = 100;
        bytes memory signature = signMessage(key, value, admin);
        vm.prank(provider2);
        oracle.updateDataFeed(key, value, signature);
        assertEq(oracle.dataFeeds(key), value);
    }

    function testInvalidSignature() public {
        bytes32 key = keccak256("price");
        uint256 value = 100;
        bytes memory signature = signMessage(key, value, provider1);
        vm.prank(provider1);
        vm.expectRevert("Invalid signature");
        oracle.updateDataFeed(key, value, signature);
    }

    function signMessage(bytes32 key, uint256 value, address signer) internal view returns (bytes memory) {
        bytes32 message = keccak256(abi.encodePacked(key, value));
        (uint8 v, bytes32 r, bytes32 s) = vm.sign(signer, message);
        return abi.encodePacked(r, s, v);
    }
}
